<template>
  <view class="page-container">
    <!-- 加载状态 -->
    <view v-if="loading" class="loading-state">
      <u-loading-icon mode="circle"></u-loading-icon>
      <text class="loading-text">加载中...</text>
    </view>

    <!-- 内容区域 -->
    <view v-else-if="detail" class="content-box">
      <text class="title">{{ detail.title }}</text>

      <view class="sub-info">
        <text>发布机构：{{ detail.org }} · {{ detail.year }}</text>
      </view>

      <!-- 操作 -->
      <view class="action-buttons">
        <u-button 
          size="mini" 
          type="primary" 
          @click="handlePreview"
          :loading="actionLoading"
        >
          在线预览
        </u-button>
        <u-button 
          size="mini" 
          plain
          @click="handleDownload"
          :loading="actionLoading"
        >
          下载 PDF
        </u-button>
      </view>

      <view class="summary-section">
        <text class="summary-text">{{ detail.summary }}</text>
      </view>

      <!-- 详细内容 -->
      <view v-if="detail.content" class="content-section">
        <text class="content-text">{{ detail.content }}</text>
      </view>
    </view>

    <!-- 空状态 -->
    <u-empty v-else mode="data" description="指南不存在或已下架"></u-empty>
  </view>
</template>

<script setup lang="ts">
import { ref } from 'vue'
import { onLoad } from '@dcloudio/uni-app'
import request from '@/utils/request'

// 类型定义
interface GuideDetail {
  id: number
  title: string
  org: string
  year: string
  summary: string
  content?: string
  pdfUrl?: string
  createdAt?: string
}

// 响应式数据
const detail = ref<GuideDetail | null>(null)
const loading = ref<boolean>(false)
const actionLoading = ref<boolean>(false)
const guideId = ref<number | null>(null)

// 加载详情
const loadDetail = async (id: number) => {
  loading.value = true
  try {
    const res = await request.get(`/api/resource/medical/guides/${id}`)
    detail.value = res.data
  } catch (error) {
    uni.__f__('error','at pages/resource/medical/GuideDetail.vue:82','加载指南详情失败:', error)
    detail.value = null
    uni.showToast({ title: '加载失败', icon: 'none' })
  } finally {
    loading.value = false
  }
}

// 通用下载并打开文件方法
const downloadAndOpenPdf = (url: string, title: string) => {
  if (!url) {
    uni.showToast({ title: '文件地址无效', icon: 'none' })
    return
  }

  actionLoading.value = true
  uni.showLoading({ title: '加载中...', mask: true })

  // 1. 下载文件
  uni.downloadFile({
    url: url,
    success: (res) => {
      if (res.statusCode === 200) {
        // 2. 打开文档
        uni.openDocument({
          filePath: res.tempFilePath,
          fileType: 'pdf',
          success: () => {
            uni.hideLoading()
          },
          fail: (err) => {
            uni.hideLoading()
            uni.__f__('error','at pages/resource/medical/GuideDetail.vue:114',err)
            uni.showToast({ title: '打开文件失败', icon: 'none' })
          }
        })
      } else {
        uni.hideLoading()
        uni.showToast({ title: '下载失败', icon: 'none' })
      }
    },
    fail: (err) => {
      uni.hideLoading()
      uni.__f__('error','at pages/resource/medical/GuideDetail.vue:125',err)
      uni.showToast({ title: '网络请求失败', icon: 'none' })
    },
    complete: () => {
      actionLoading.value = false
    }
  })
}

// 在线预览
const handlePreview = () => {
  if (detail.value?.pdfUrl) {
    downloadAndOpenPdf(detail.value.pdfUrl, detail.value.title)
  } else {
    uni.showToast({ title: '暂无PDF文件', icon: 'none' })
  }
}

// 下载 PDF
const handleDownload = () => {
  if (detail.value?.pdfUrl) {
    downloadAndOpenPdf(detail.value.pdfUrl, detail.value.title)
  } else {
    uni.showToast({ title: '暂无PDF文件', icon: 'none' })
  }
}

// 生命周期：页面加载时获取参数
onLoad((options) => {
  if (options.id) {
    guideId.value = Number(options.id)
    loadDetail(guideId.value)
  } else {
    uni.showToast({ title: '缺少指南ID', icon: 'none' })
    setTimeout(() => {
      uni.navigateBack()
    }, 1500)
  }
})
</script>

